type Transform<U, P> = {
  [P in keyof P]: P extends infer T ? T extends A ? T : never : never,
  [P in keyof P]: P extends A ? P : never
}

// Example usage:
interface User{
  id: number,
  name: string,
  age: number
}

type UserTransform = Transform<User, User>
